import sys
import math

def is_prime(x: int) -> bool:
    """return True iff x is a prime (x <= 20000 in this problem)"""
    if x < 2:
        return False
    if x % 2 == 0:
        return x == 2
    r = int(math.isqrt(x))
    for d in range(3, r + 1, 2):
        if x % d == 0:
            return False
    return True

def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]

        total = sum(a)

        if not is_prime(total):
            # whole array works
            out_lines.append(str(n))
            out_lines.append(' '.join(str(i) for i in range(1, n + 1)))
        else:
            # total is prime -> odd, remove any odd element
            odd_idx = -1
            for i, val in enumerate(a):
                if val % 2 == 1:
                    odd_idx = i + 1          # 1‑based index
                    break
            # odd_idx must exist because total is odd
            indices = [str(i) for i in range(1, n + 1) if i != odd_idx]
            out_lines.append(str(n - 1))
            out_lines.append(' '.join(indices))

    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

