import sys
import math

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]

        # 1. count how many numbers have each bit set
        cnt = [0] * 30
        for v in a:
            # unroll a little for speed (optional)
            for b in range(30):
                if (v >> b) & 1:
                    cnt[b] += 1

        # 2. compute GCD of all non‑zero counts
        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)

        # 3. produce answer
        if g == 0:                     # array already all zeros
            out_lines.append(' '.join(str(k) for k in range(1, n + 1)))
        else:
            divisors = []
            d = 1
            # enumerate divisors of g
            while d * d <= g:
                if g % d == 0:
                    if d <= n:
                        divisors.append(d)
                    other = g // d
                    if other != d and other <= n:
                        divisors.append(other)
                d += 1
            divisors.sort()
            out_lines.append(' '.join(map(str, divisors)))

    sys.stdout.write('\n'.join(out_lines))

